impl Solution { pub fn closest_cost(base_costs: Vec<i32>, topping_costs: Vec<i32>, target: i32) -> i32 { let mut black_res = base_costs[0]; for black_b in base_costs { Self::black_dfs(0, black_b, &topping_costs, target, &mut black_res); } black_res } fn black_dfs(i: usize, cur: i32, tops: &Vec<i32>, tar: i32, res: &mut i32) { if (cur - tar).abs() < (*res - tar).abs() || ((cur - tar).abs() == (*res - tar).abs() && cur < *res) { *res = cur; } if i == tops.len() || cur > tar { return; } for c in 0..=2 { Self::black_dfs(i + 1, cur + tops[i] * c, tops, tar, res); } } }